//! Asynchronous RPC-style worker API framework for Crack projects.
//!
//! This crate provides a flexible framework for defining and invoking
//! asynchronous API methods across process or thread boundaries. It is designed
//! for use in both native and WebAssembly targets.
//!
//! # Architecture
//!
//! * **API definitions** — Define method signatures using the [`api::api_method_macros`]
//!   traits and macros. Methods are grouped into *API groups*.
//! * **Client** — [`api::ApiClient`] sends typed requests to a worker and awaits
//!   typed responses. It handles request/response correlation transparently.
//! * **Worker** — [`crack_worker`] runs an event loop that receives requests,
//!   dispatches them to registered implementations, and sends back responses.
//! * **Transport** — [`crack_worker::WorkerPipe`] provides the underlying
//!   message-passing channel (MPSC) between client and worker.
//!
//! # Feature highlights
//!
//! * Cross-platform: works on native targets and WebAssembly (via `n0_future`).
//! * Type-safe: arguments and return values are serialized with `postcard`
//!   and type-checked via traits.
//! * Async-first: all I/O uses `async`/`await` via `n0_future` task abstraction.
//!
//! # Example
//!
//! ```ignore
//! // Define an API group and method
//! declare_api_group2! {
//!     MyApiGroup,
//!     [
//!         (MyMethod, MyArg, MyRet),
//!     ]
//! }
//!
//! // Client side
//! let client = ApiClient::new(pipe);
//! let result = client.call::<MyMethod>(MyArg { ... }).await?;
//! ```
//!
//! See the [`api`] and [`crack_worker`] modules for detailed usage.

pub mod api;
pub mod crack_worker;

/// Re-export of cross-platform async utilities.
pub use _crack_utils;
/// Re-export of error handling crate.
pub use anyhow;
/// Re-export of async trait support.
pub use async_trait;
/// Re-export of futures utilities.
pub use futures;
/// Re-export of `paste` macro for macro-based API declarations.
pub use paste;

//! Public API surface for the asynchronous worker RPC framework.
//!
//! This module re-exports the client-facing types and the macro-based API
//! declaration machinery. See sub-modules for details:
//!
//! * [`api_client`] — [`ApiClient`] for sending typed requests to a worker.
//! * [`api_method_macros`] — Traits and macros for declaring API groups and methods.
//! * [`api_worker_declarations`] — Example worker API declarations.

pub mod api_client;
pub mod api_method_macros;
pub mod api_worker_declarations;

use std::{collections::HashMap, sync::Arc};

use _crack_utils::{n0_future, random_u32};

use crate::{
    api::api_method_macros::ApiMethodDecl,
    crack_worker::{WorkerMessage, WorkerPipe},
};

/// Client-side handle for invoking worker API methods.
///
/// Holds a sender to the worker's request channel, an in-flight request
/// map, and a background task that drains the worker's response channel
/// and routes replies back to the waiting callers.
#[derive(Clone)]
pub struct ApiClient {
    /// Sender half of the worker request channel.
    tx: Arc<tokio::sync::mpsc::Sender<WorkerMessage>>,
    /// In-flight request map: msg_id -> oneshot sender for the reply.
    _memory: Arc<tokio::sync::Mutex<ApiClientMemory>>,
    /// Background task that receives responses and wakes up waiters.
    _thread: Arc<_crack_utils::n0_future::task::JoinHandle<anyhow::Result<()>>>,
}

struct ApiClientMemory {
    map: HashMap<u32, MessageLater>,
}

/// Internal holder for the oneshot channel that completes when the
/// worker replies to a specific request ID.
pub struct MessageLater {
    reply_to: tokio::sync::oneshot::Sender<WorkerMessage>,
}

/// Background task that drains the worker's response channel.
///
/// For each `WorkerMessage` received, looks up the corresponding
/// `oneshot::Sender` in `ApiClientMemory` and forwards the message.
/// If no sender is found (stale/duplicate response), logs a warning.
async fn client_thread(
    _memory: Arc<tokio::sync::Mutex<ApiClientMemory>>,
    mut rx_pipe: tokio::sync::mpsc::Receiver<WorkerMessage>,
) -> anyhow::Result<()> {
    while let Some(ret) = rx_pipe.recv().await {
        let ret_id = ret.msg_id;

        let Some(connect) = ({ _memory.lock().await.map.remove(&ret_id) }) else {
            tracing::warn!("got a message back but no known ID, id={}", ret_id);
            continue;
        };
        let _r = connect.reply_to.send(ret);
        if let Err(_e) = _r {
            tracing::info!("Failed to send back worker message: id={}", _e.msg_id);
            continue;
        }
    }
    Ok(())
}

impl ApiClient {
    /// Creates a new `ApiClient` from a `WorkerPipe`.
    ///
    /// Spawns the background `client_thread` to handle responses.
    pub fn new(pipe: WorkerPipe) -> Self {
        let _memory = Arc::new(tokio::sync::Mutex::new(ApiClientMemory {
            map: HashMap::new(),
        }));
        let _memory2 = _memory.clone();
        Self {
            tx: Arc::new(pipe.req_tx),
            _thread: Arc::new(n0_future::task::spawn(client_thread(
                _memory2,
                pipe.resp_rx,
            ))),
            _memory,
        }
    }

    /// Invokes an API method on the worker and awaits the result.
    ///
    /// `T` must implement [`ApiMethodDecl`] (generated by the API macros).
    /// The argument is serialized with `postcard`, sent to the worker, and
    /// the response is deserialized into `T::Ret`.
    ///
    /// # Errors
    /// Returns an error if serialization, channel send, or response
    /// deserialization fails, or if the worker returns an error.
    pub async fn call<T: ApiMethodDecl>(&self, arg: T::Arg) -> anyhow::Result<T::Ret> {
        let arg = postcard::to_stdvec(&arg)?;
        let msg_type = T::fullname();
        let req_id = random_u32();

        let msg = WorkerMessage {
            msg_content: arg,
            msg_id: req_id,
            msg_type,
        };
        let (one_tx, one_rx) = tokio::sync::oneshot::channel::<WorkerMessage>();

        let _ins = {
            let _memory = &mut self._memory.lock().await.map;

            _memory.insert(req_id, MessageLater { reply_to: one_tx })
        };
        self.tx.send(msg).await?;

        let ret = one_rx.await?;
        match ret.msg_type.as_str() {
            "return" => Ok(postcard::from_bytes(&ret.msg_content)?),
            "error_deserialize_arg" => Err(anyhow::anyhow!(
                "worker failed to deserialize arg: {}",
                String::from_utf8_lossy(&ret.msg_content)
            )),
            "error_serialize_ret" => Err(anyhow::anyhow!(
                "worker failed to serialize return: {}",
                String::from_utf8_lossy(&ret.msg_content)
            )),
            _ => Err(anyhow::anyhow!(
                "unexpected worker message type: {}",
                ret.msg_type
            )),
        }
    }
}

use crate::crack_worker::WorkerMessage;
use serde::{Deserialize, Serialize};

/// Marker trait implemented by a type representing an API group.
///
/// Each group has a static `GROUP` identifier (e.g., `"WorkerApi"`).
pub trait ApiGroupDecl {
    /// The static name of this API group.
    const GROUP: &'static str;
}

/// Trait providing static metadata about the methods in an API group.
///
/// Implemented by the `declare_api_group2!` macro for the group's
/// zero-sized type.
pub trait ApiGroupMethods {
    /// Returns the group's static name (same as `ApiGroupDecl::GROUP`).
    fn grp_name(&self) -> &'static str;
    /// Returns a slice of [`ApiMethodInfo`] describing each method.
    fn method_infos(&self) -> &'static [ApiMethodInfo];
}

/// Extension of [`ApiGroupMethods`] that also provides the executable
/// implementations for each method.
///
/// Implemented by `implement_api_group2!` after the user supplies the
/// implementation functions.
pub trait ApiGroupImpls: ApiGroupMethods {
    /// Returns a slice of [`ApiMethodImpl`] containing the callable
    /// wrappers for each method.
    fn method_impls(&self) -> &'static [ApiMethodImpl];
}

/// Zero-sized type carrying only a group name.
///
/// Used internally by the macro machinery when a full group implementation
/// is not yet available (e.g., in `declare_api_group2!`).
#[derive(Clone, Copy, Debug)]
pub struct ApiGroupDeclStatic {
    /// The static group name.
    pub group: &'static str,
}

/// Trait implemented by each concrete API method type.
///
/// Generated by the `declare_api_method_before2!` macro. It associates:
/// - `NAME`: the method's static name (e.g., `"Ping"`).
/// - `Grp`: the group type implementing [`ApiGroupDecl`].
/// - `Arg`: the serialized argument type (must be `Clone + Debug + Serialize + Deserialize + Send + 'static`).
/// - `Ret`: the serialized return type (must be `Debug + Serialize + Deserialize + Send + 'static`).
pub trait ApiMethodDecl {
    /// Static method name.
    const NAME: &'static str;
    /// The API group this method belongs to.
    type Grp: ApiGroupDecl;
    /// Argument type for the RPC call.
    type Arg: Clone + std::fmt::Debug + Serialize + for<'a> Deserialize<'a> + 'static + Send;
    /// Return type for the RPC call.
    type Ret: std::fmt::Debug + Serialize + for<'a> Deserialize<'a> + 'static + Send;

    /// Returns the fully-qualified method name as `"Group.Method"`.
    fn fullname() -> String {
        let a = <Self::Grp as ApiGroupDecl>::GROUP;
        let b = Self::NAME;
        format!("{a}.{b}")
    }

    /// Wraps a user-provided async function into the worker's message
    /// processing pipeline.
    ///
    /// This handles:
    /// - Deserializing the argument from `postcard` bytes.
    /// - Calling the user function and measuring execution time.
    /// - Serializing the result (or error) back to `postcard` bytes.
    /// - Constructing a `WorkerMessage` response with timing diagnostics.
    ///
    /// The returned future is boxed and `Send` so it can be spawned on the
    /// worker runtime.
    #[allow(clippy::type_complexity)]
    fn wrap_impl(
        _func: fn(
            Self::Arg,
        ) -> std::pin::Pin<
            Box<dyn futures::Future<Output = anyhow::Result<Self::Ret>> + Send>,
        >,
        msg: WorkerMessage,
    ) -> std::pin::Pin<Box<dyn futures::Future<Output = WorkerMessage> + Send>> {
        let msg_id = msg.msg_id;
        let arg = postcard::from_bytes::<Self::Arg>(&msg.msg_content);

        // let arg = post
        // let ret = func(arg);
        // let v = postcard::to_vec(value)
        use futures::FutureExt;
        async move {
            let arg = match arg {
                Ok(o) => o,
                Err(e) => {
                    return WorkerMessage {
                        msg_id,
                        msg_type: "error_deserialize_arg".to_string(),
                        msg_content: format!("{e:#?}").as_bytes().to_vec(),
                    };
                }
            };
            let start = _crack_utils::get_timestamp_now_ms();
            let ret = _func(arg).await;
            let elapsed_func = _crack_utils::get_timestamp_now_ms() - start;

            let start_serialize = _crack_utils::get_timestamp_now_ms();
            let ret: Result<<Self as ApiMethodDecl>::Ret, String> =
                ret.map_err(|e| format!("{e:#?}"));

            let msg_content: Vec<u8> = match postcard::to_stdvec(&ret) {
                Ok(m) => m,
                Err(e) => {
                    return WorkerMessage {
                        msg_id,
                        msg_type: "error_serialize_ret".to_string(),
                        msg_content: format!("{e:#?}").as_bytes().to_vec(),
                    };
                }
            };
            let elapsed_serialize = _crack_utils::get_timestamp_now_ms() - start_serialize;
            tracing::debug!(
                "Worker: API call {} took run={} ms, serialize={} ms (size={} bytes)",
                Self::fullname(),
                elapsed_func,
                elapsed_serialize,
                msg_content.len()
            );

            WorkerMessage {
                msg_id,
                msg_type: "return".to_string(),
                msg_content,
            }
        }
        .boxed()
    }
}

/// Static metadata describing a single API method.
///
/// Created by `declare_api_method_after2!` and collected into a slice by
/// `declare_api_group2!`.
#[derive(Clone, Debug)]
pub struct ApiMethodInfo {
    /// Method name (e.g., `"Ping"`).
    pub name: &'static str,
    /// Group name (e.g., `"WorkerApi"`).
    pub grp: &'static str,
    /// Argument type as a string (e.g., `"()"`).
    pub arg: &'static str,
    /// Return type as a string (e.g., `"()"`).
    pub ret: &'static str,
}

/// Executable implementation of an API method.
///
/// Created by `declare_api_method_impl_after2!` and collected by
/// `implement_api_group2!`. The `func` field is a boxed future wrapper
/// produced by `wrap_impl`.
#[derive(Clone, Debug)]
pub struct ApiMethodImpl {
    /// Method name (e.g., `"Ping"`).
    pub name: &'static str,
    /// Group name (e.g., `"WorkerApi"`).
    pub grp: &'static str,
    /// Callable wrapper that takes a `WorkerMessage` and returns a
    /// `WorkerMessage` future.
    pub func:
        fn(WorkerMessage) -> std::pin::Pin<Box<dyn futures::Future<Output = WorkerMessage> + Send>>,
}

impl ApiMethodImpl {
    /// Returns the fully-qualified method name as `"Group.Method"`.
    pub fn fullname(&self) -> String {
        let b = self.name;
        let a = self.grp;
        format!("{a}.{b}")
    }
}

impl ApiMethodInfo {
    /// Returns the fully-qualified method name as `"Group.Method"`.
    pub fn fullname(&self) -> String {
        let b = self.name;
        let a = self.grp;
        format!("{a}.{b}")
    }
}

/// Macro: declares the zero-sized method type and implements [`ApiMethodDecl`].
///
/// Users typically invoke this indirectly via `declare_api_group2!`.
#[macro_export]
macro_rules! declare_api_method_before2 {
    ($grp:tt, $name:tt, $arg:ty, $ret:ty) => {
        $crate::paste::paste! {
            #[derive(Debug, Clone, Copy)]
            pub struct $name;
            impl $crate::api::api_method_macros::ApiMethodDecl for $name {
                const NAME: &str = stringify!($name);
                type Grp = $grp;
                type Arg = $arg;
                type Ret = $ret;
            }
        }
    };
}

/// Macro: produces an [`ApiMethodInfo`] struct literal for a method.
///
/// Used internally by `declare_api_group2!`.
#[macro_export]
macro_rules! declare_api_method_after2 {
    ($grp:tt, $name:tt, $arg:ty, $ret:ty) => {
        $crate::paste::paste! {
                $crate::api::api_method_macros::ApiMethodInfo {
                    name: stringify!($name),
                    grp: stringify!($grp),
                    arg: stringify!($arg),
                    ret: stringify!($ret),
                }
        }
    };
}

/// Macro: declares an API group and all its methods at once.
///
/// Syntax:
/// ```ignore
/// declare_api_group2! {
///     GroupName,
///     [
///         (MethodName, ArgType, RetType),
///         ...
///     ]
/// }
/// ```
///
/// This expands to:
/// - A zero-sized `struct GroupName` implementing [`ApiGroupDecl`] and
///   [`ApiGroupMethods`].
/// - For each method, a zero-sized type implementing [`ApiMethodDecl`].
#[macro_export]
macro_rules! declare_api_group2 {
    ($name:tt, [$(($mname:tt, $arg:ty, $ret:ty),)*]) => {
        #[derive(Debug, Copy, Clone)]
        pub struct $name;
        impl $crate::api::api_method_macros::ApiGroupDecl for $name {
            const GROUP: &str = stringify!($name);
        }
        $(
            $crate::declare_api_method_before2!( $name, $mname, $arg, $ret);
        )*

        impl $crate::api::api_method_macros::ApiGroupMethods for $name {
            fn grp_name(&self) -> &'static str {stringify!($name)}
            fn method_infos(&self)
            -> &'static [$crate::api::api_method_macros::ApiMethodInfo]
            {
            &[
                $(
                    $crate::declare_api_method_after2!(
                        $name, $mname, $arg, $ret),
                )*
            ]
            }
        }
    };
}

/// Macro: creates the wrapper functions that adapt a user async function
/// into the worker's `WorkerMessage` -> `WorkerMessage` calling convention.
///
/// Users typically invoke this via `implement_api_group2!`.
#[macro_export]
macro_rules! declare_api_method_impl_before2 {
    ($name:tt, $func:expr) => {
        $crate::paste::paste! {

            #[allow(nonstandard_style)]
            fn [<__ $name __wrapper1>](
                x: <$name as $crate::api::api_method_macros::ApiMethodDecl>::Arg
            ) -> std::pin::Pin<Box<
                dyn $crate::futures::Future<
                    Output=$crate::anyhow::Result<
                        <$name as $crate::api::api_method_macros::ApiMethodDecl>::Ret
                    >
                >+Send
            >> {
                use $crate::futures::FutureExt;
                $func(x).boxed()
            }


            #[allow(nonstandard_style)]
            fn [<__ $name __wrapper_outer>] (msg: $crate::crack_worker::WorkerMessage) -> std::pin::Pin<Box<
                dyn $crate::futures::Future<Output=$crate::crack_worker::WorkerMessage>+Send
            >> {
                <$name as $crate::api::api_method_macros::ApiMethodDecl>::wrap_impl(
                    [<__ $name __wrapper1>],
                    msg,
                )
            }

        }
    };
}

/// Macro: produces an [`ApiMethodImpl`] struct literal referencing the
/// wrapper created by `declare_api_method_impl_before2!`.
///
/// Used internally by `implement_api_group2!`.
#[macro_export]
macro_rules! declare_api_method_impl_after2 {
    ($name:tt, $func:expr) => {
        $crate::paste::paste! {

            $crate::api::api_method_macros::ApiMethodImpl {
                func: [<__ $name __wrapper_outer>],
                name: <$name as $crate::api::api_method_macros::ApiMethodDecl>::NAME,
                grp: <<$name as $crate::api::api_method_macros::ApiMethodDecl>::Grp
                as $crate::api::api_method_macros::ApiGroupDecl>::GROUP,
            }
        }
    };
}

/// Macro: implements [`ApiGroupImpls`] for a group by supplying the
/// implementation functions for each method.
///
/// Syntax:
/// ```ignore
/// implement_api_group2! {
///     GroupName,
///     [
///         (MethodName, async_function),
///         ...
///     ]
/// }
/// ```
///
/// Each `async_function` must have signature
/// `fn(Arg) -> Pin<Box<dyn Future<Output = anyhow::Result<Ret>> + Send>>`.
#[macro_export]
macro_rules! implement_api_group2 {
    ($name:tt, [$(($mname:tt, $arg:expr),)*]) => {
           $(
                $crate::declare_api_method_impl_before2!($mname, $arg);
            )*
        impl $crate::api::api_method_macros::ApiGroupImpls for $name {
            fn method_impls(&self) -> &'static [$crate::api::api_method_macros::ApiMethodImpl] {
            &[
            $(
                $crate::declare_api_method_impl_after2!($mname, $arg),
            )*
                ]
            }
        }
    };
}

#[cfg(test)]
mod tests {
    use super::*;
    #[cfg(target_arch = "wasm32")]
    use wasm_bindgen_test::wasm_bindgen_test as test;

    #[test]
    fn smoke_method_info_and_impl_fullname() {
        let info = ApiMethodInfo {
            name: "Ping",
            grp: "Grp",
            arg: "()",
            ret: "()",
        };
        assert_eq!(info.fullname(), "Grp.Ping");

        let decl = ApiGroupDeclStatic { group: "Grp" };
        assert_eq!(decl.group, "Grp");
    }
}

use _crack_utils::sleep_ms;

use crate::declare_api_group2;
use crate::implement_api_group2;

declare_api_group2! {
    WorkerApiGroup2,
    [
        (WorkerPing, (), ()),
    ]
}

implement_api_group2! {
    WorkerApiGroup2,
    [
        (WorkerPing, worker_ping),
    ]
}

pub async fn worker_ping(_x: ()) -> anyhow::Result<()> {
    sleep_ms(1).await;
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::api::api_method_macros::{ApiGroupMethods, ApiMethodDecl};

    async fn declarations_body() {
        // The macros above must declare + implement exactly one method.
        assert_eq!(
            <WorkerPing as ApiMethodDecl>::fullname(),
            "WorkerApiGroup2.WorkerPing"
        );
        let infos = WorkerApiGroup2.method_infos();
        assert_eq!(infos.len(), 1);
        assert_eq!(infos[0].fullname(), "WorkerApiGroup2.WorkerPing");
        worker_ping(()).await.expect("worker_ping should succeed");
    }

    #[cfg(not(target_arch = "wasm32"))]
    #[tokio::test]
    async fn smoke_worker_api_group2_declarations() {
        declarations_body().await;
    }

    #[cfg(target_arch = "wasm32")]
    #[wasm_bindgen_test::wasm_bindgen_test]
    async fn smoke_worker_api_group2_declarations() {
        declarations_body().await;
    }
}

pub mod api_worker;

pub struct WorkerPipe {
    pub req_tx: tokio::sync::mpsc::Sender<WorkerMessage>,
    pub resp_rx: tokio::sync::mpsc::Receiver<WorkerMessage>,
}

#[derive(Clone, serde::Serialize, serde::Deserialize, Debug)]
pub struct WorkerMessage {
    pub msg_id: u32,
    pub msg_type: String,
    pub msg_content: Vec<u8>,
}

#[async_trait::async_trait(?Send)]
pub trait WorkerLoaderFactory {
    async fn load_worker(&self) -> anyhow::Result<WorkerPipe>;
}

#[cfg(test)]
mod tests {
    use super::*;
    #[cfg(target_arch = "wasm32")]
    use wasm_bindgen_test::wasm_bindgen_test as test;

    #[test]
    fn smoke_worker_message_serde_roundtrip() {
        let msg = WorkerMessage {
            msg_id: 7,
            msg_type: "ping".to_string(),
            msg_content: b"abcd".to_vec(),
        };
        let bytes = postcard::to_stdvec(&msg).unwrap();
        let back: WorkerMessage = postcard::from_bytes(&bytes).unwrap();
        assert_eq!(back.msg_id, 7);
        assert_eq!(back.msg_type, "ping");
        assert_eq!(back.msg_content, b"abcd".to_vec());
    }
}

use std::{
    collections::{BTreeMap, BTreeSet},
    sync::Arc,
};

use crate::{
    api::api_method_macros::{ApiGroupImpls, ApiMethodImpl, ApiMethodInfo},
    crack_worker::WorkerMessage,
};

pub struct ApiImplMapping {
    impl_fns: BTreeMap<String, ApiMethodImpl>,
    info_fns: BTreeMap<String, ApiMethodInfo>,
}

pub fn make_api_mapping(groups: Vec<Arc<dyn ApiGroupImpls>>) -> Arc<ApiImplMapping> {
    for item in &groups {
        tracing::info!("Loading API GROUP: {}", item.grp_name());
    }
    let mut impl_fns = BTreeMap::new();
    let mut info_fns = BTreeMap::new();

    for i in _get_infos2(groups.clone()) {
        let _r = info_fns.insert(i.fullname(), i.clone());
        if _r.is_some() {
            panic!("Duplicate declaration: fullname()={}", i.fullname())
        }
    }

    for i in _get_impls2(groups.clone()) {
        let _r = impl_fns.insert(i.fullname(), i.clone());
        if _r.is_some() {
            panic!("Duplicate implementation: fullname()={}", i.fullname())
        }
    }

    if impl_fns.len() != info_fns.len() {
        tracing::info!(
            "Mismatch in count of {} declarations vs. {} implementations!",
            info_fns.len(),
            impl_fns.len()
        );
        // TODO: get which is missing...
        let keys_a = BTreeSet::from_iter(info_fns.keys().cloned());
        let keys_b = BTreeSet::from_iter(impl_fns.keys().cloned());

        let diff_a = keys_a.difference(&keys_b).collect::<Vec<_>>();
        let diff_b = keys_b.difference(&keys_a).collect::<Vec<_>>();

        tracing::info!("Declarations that are not implemented: {:?}", diff_a);
        tracing::info!("Implementations that are not declared: {:?}", diff_b);

        panic!(
            "
        Mismatch in count of {} declarations vs. {} implementations!
        Declarations that are not implemented: {:?}
        Implementations that are not declared: {:?}
        ",
            info_fns.len(),
            impl_fns.len(),
            diff_a,
            diff_b
        );
    }

    tracing::info!(
        "Api Mapping Singleton Created! func impl count = {}",
        info_fns.len()
    );
    for info_fn in &info_fns {
        tracing::info!("Loaded API Implementation function: {}", info_fn.0);
    }

    Arc::new(ApiImplMapping { impl_fns, info_fns })
}

