        v.append(&mut v2);
    }
    v
}

fn _get_impls2(grps: Vec<Arc<dyn ApiGroupImpls>>) -> Vec<ApiMethodImpl> {
    let mut v = vec![];
    for grp in grps {
        let mut v2 = grp.method_impls().to_vec();
        v.append(&mut v2);
    }
    v
